proof fn phi_1_stable_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>)
    requires
        stable(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex) ==> forall |i: nat| p.satisfied_by(#[trigger] ex.suffix(i)),
{
    stable_unfold::<int>(ex, p);
}

proof fn phi_2_stable_and_valid(p: TempPred<int>, q: TempPred<int>)
    requires
        valid(stable(p)),
        valid(stable(q)),
    ensures
        valid(stable(p.and(q))),
{
    stable_and_temp::<int>(p, q);
}
